<body>
    <div class="container">
        <svg id="fractalSvg" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 600 600">
            <g id="fractalGroup" fill="#2a7fff" opacity="0.9"></g>
        </svg>

        <div class="controls">
            <button id="zoomIn" title="放大 (深度 +1)">🔍 +</button>
            <button id="zoomOut" title="缩小 (深度 -1)">🔍 −</button>
            <button id="moveUp" title="上移">↑</button>
            <button id="moveDown" title="下移">↓</button>
            <button id="moveLeft" title="左移">←</button>
            <button id="moveRight" title="右移">→</button>
            <button id="reset" title="重置视图">↺</button>
        </div>

        <div class="info">
            <span id="depthDisplay">深度: 6</span>
            <span id="zoomDisplay">缩放: 1.0x</span>
            <span id="trianglesDisplay">三角形: 0</span>
        </div>
        <div class="note">拖动 SVG 也可平移 | 鼠标滚轮缩放</div>
    </div>

    <script>
        (function() {
            'use strict';

            // ----- 配置与状态 -----
            const SVG_NS = 'http://www.w3.org/2000/svg';
            const svg = document.getElementById('fractalSvg');
            const fractalGroup = document.getElementById('fractalGroup');

            // 初始 viewBox (坐标系)
            let vb = { x: 0, y: 0, w: 600, h: 600 };
            const SVG_PIXEL_SIZE = 600;          // SVG 元素像素尺寸 (宽高一致)
            const REF_WIDTH = 600;                // 用于缩放因子计算
            const MIN_DEPTH = 6;
            const MAX_DEPTH = 12;
            const INITIAL_SIDE = 560;             // 初始大三角形边长 (约560个坐标单位)

            let currentDepth = MIN_DEPTH;

            // 已添加的三角形映射: key -> <polygon> 元素
            const pathMap = new Map();

            // 防抖定时器
            let updateTimer = null;

            // UI 元素
            const depthDisplay = document.getElementById('depthDisplay');
            const zoomDisplay = document.getElementById('zoomDisplay');
            const trianglesDisplay = document.getElementById('trianglesDisplay');

            // ----- 工具函数 -----
            function triangleKey(pts) {
                return pts.map(p => `${p.x.toFixed(2)},${p.y.toFixed(2)}`).join('|');
            }

            function rectsIntersect(r1, r2) {
                return !(r1.x + r1.w <= r2.x || r2.x + r2.w <= r1.x ||
                         r1.y + r1.h <= r2.y || r2.y + r2.h <= r1.y);
            }

            function triangleBounds(tri) {
                const xs = tri.map(p => p.x);
                const ys = tri.map(p => p.y);
                const minX = Math.min(...xs);
                const maxX = Math.max(...xs);
                const minY = Math.min(...ys);
                const maxY = Math.max(...ys);
                return { x: minX, y: minY, w: maxX - minX, h: maxY - minY };
            }

            // 根据当前 viewBox 计算深度 (对数映射)
            function computeDepth() {
                const factor = REF_WIDTH / vb.w;
                const depth = Math.floor(MIN_DEPTH + Math.log2(factor));
                return Math.max(MIN_DEPTH, Math.min(MAX_DEPTH, depth));
            }

            // 更新 UI 信息
            function updateInfo() {
                const factor = (REF_WIDTH / vb.w).toFixed(2);
                zoomDisplay.textContent = `缩放: ${factor}x`;
                depthDisplay.textContent = `深度: ${currentDepth}`;
                trianglesDisplay.textContent = `三角形: ${pathMap.size}`;
            }

            // ----- 递归生成可见三角形 (带视口裁剪 + 子像素终止) -----
            // 参数:
            //   vertices  - 三角形三个顶点 [{x,y}, ...]
            //   depth     - 当前递归深度 (从0开始)
            //   maxDepth  - 最大允许深度 (由外部计算得到)
            //   viewRect  - 当前视口矩形 {x, y, w, h}
            //   sideLength - 当前三角形的特征边长 (用于像素尺寸检查)
            // 返回: 可见三角形列表 [{key, points}]
            function generateVisibleTriangles(vertices, depth, maxDepth, viewRect, sideLength) {
                // 1. 视口裁剪：如果包围盒与视口不相交，跳过整个子树
                const bounds = triangleBounds(vertices);
                if (!rectsIntersect(bounds, viewRect)) {
                    return [];
                }

                // 2. 计算屏幕像素尺寸: 当前边长在屏幕上的像素长度
                const scale = SVG_PIXEL_SIZE / viewRect.w;   // 1个坐标单位对应的屏幕像素数
                const screenSize = sideLength * scale;

                // 3. 终止条件:
                //    - 达到最大深度
                //    - 子分形在屏幕上小于1像素 (任何边长小于1像素即不可见细节)
                if (depth >= maxDepth || screenSize < 1) {
                    const key = triangleKey(vertices);
                    return [{ key, points: vertices }];
                }

                // 4. 否则继续递归细分 (Sierpinski 三向细分)
                const [a, b, c] = vertices;
                const midAB = { x: (a.x + b.x) / 2, y: (a.y + b.y) / 2 };
                const midBC = { x: (b.x + c.x) / 2, y: (b.y + c.y) / 2 };
                const midCA = { x: (c.x + a.x) / 2, y: (c.y + a.y) / 2 };

                const sub1 = [a, midAB, midCA];
                const sub2 = [b, midBC, midAB];
                const sub3 = [c, midCA, midBC];

                const newSide = sideLength / 2;
                let results = [];
                results = results.concat(generateVisibleTriangles(sub1, depth + 1, maxDepth, viewRect, newSide));
                results = results.concat(generateVisibleTriangles(sub2, depth + 1, maxDepth, viewRect, newSide));
                results = results.concat(generateVisibleTriangles(sub3, depth + 1, maxDepth, viewRect, newSide));
                return results;
            }

            // ----- 核心更新函数 (全量 / 增量) -----
            function updateFractal() {
                // 取消待处理的更新
                if (updateTimer) {
                    clearTimeout(updateTimer);
                    updateTimer = null;
                }

                const newDepth = computeDepth();
                const effectiveDepth = Math.min(newDepth, MAX_DEPTH); // 受最大深度限制
                const viewRect = { x: vb.x, y: vb.y, w: vb.w, h: vb.h };

                // 如果深度改变 -> 完全重建
                if (newDepth !== currentDepth) {
                    currentDepth = newDepth;   // 更新深度信息
                    fractalGroup.innerHTML = '';
                    pathMap.clear();

                    // 初始大三角形 (顶点坐标)
                    const baseTriangle = [
                        { x: 300, y: 20 },
                        { x: 20, y: 580 },
                        { x: 580, y: 580 }
                    ];
                    const visible = generateVisibleTriangles(baseTriangle, 0, effectiveDepth, viewRect, INITIAL_SIDE);

                    const fragment = document.createDocumentFragment();
                    for (const item of visible) {
                        const poly = document.createElementNS(SVG_NS, 'polygon');
                        const pointsStr = item.points.map(p => `${p.x},${p.y}`).join(' ');
                        poly.setAttribute('points', pointsStr);
                        poly.setAttribute('fill', '#2a7fff');
                        fragment.appendChild(poly);
                        pathMap.set(item.key, poly);
                    }
                    fractalGroup.appendChild(fragment);
                    updateInfo();
                    return;
                }

                // 深度不变 -> 增量更新 (避免重复计算)
                const baseTriangle = [
                    { x: 300, y: 20 },
                    { x: 20, y: 580 },
                    { x: 580, y: 580 }
                ];
                const visible = generateVisibleTriangles(baseTriangle, 0, effectiveDepth, viewRect, INITIAL_SIDE);
                const newKeys = new Set(visible.map(item => item.key));

                // 1. 移除不再可见的三角形
                for (const [key, elem] of pathMap) {
                    if (!newKeys.has(key)) {
                        elem.remove();
                        pathMap.delete(key);
                    }
                }

                // 2. 添加新视口内缺失的三角形
                const fragment = document.createDocumentFragment();
                for (const item of visible) {
                    if (!pathMap.has(item.key)) {
                        const poly = document.createElementNS(SVG_NS, 'polygon');
                        const pointsStr = item.points.map(p => `${p.x},${p.y}`).join(' ');
                        poly.setAttribute('points', pointsStr);
                        poly.setAttribute('fill', '#2a7fff');
                        fragment.appendChild(poly);
                        pathMap.set(item.key, poly);
                    }
                }
                fractalGroup.appendChild(fragment);

                updateInfo();
            }

            // ----- 防抖更新 (避免频繁渲染) -----
            function scheduleUpdate(delay = 80) {
                if (updateTimer) clearTimeout(updateTimer);
                updateTimer = setTimeout(updateFractal, delay);
            }

            // ----- 视图变换操作 -----
            function zoomIn() {
                const cx = vb.x + vb.w / 2;
                const cy = vb.y + vb.h / 2;
                vb.w /= 2;
                vb.h /= 2;
                vb.x = cx - vb.w / 2;
                vb.y = cy - vb.h / 2;
                applyViewBox();
                scheduleUpdate();
            }

            function zoomOut() {
                const cx = vb.x + vb.w / 2;
                const cy = vb.y + vb.h / 2;
                vb.w *= 2;
                vb.h *= 2;
                vb.x = cx - vb.w / 2;
                vb.y = cy - vb.h / 2;
                applyViewBox();
                scheduleUpdate();
            }

            function move(dx, dy) {
                vb.x += dx;
                vb.y += dy;
                applyViewBox();
                scheduleUpdate();
            }

            function resetView() {
                vb = { x: 0, y: 0, w: 600, h: 600 };
                applyViewBox();
                scheduleUpdate(0);
            }

            function applyViewBox() {
                svg.setAttribute('viewBox', `${vb.x} ${vb.y} ${vb.w} ${vb.h}`);
            }

            // ----- 鼠标拖拽平移 -----
            let isDragging = false;
            let dragStart = { x: 0, y: 0 };
            let vbStart = { x: 0, y: 0 };

            svg.addEventListener('mousedown', (e) => {
                if (e.button !== 0) return;
                isDragging = true;
                const rect = svg.getBoundingClientRect();
                dragStart.x = e.clientX - rect.left;
                dragStart.y = e.clientY - rect.top;
                vbStart = { ...vb };
                svg.style.cursor = 'grabbing';
                e.preventDefault();
            });

            window.addEventListener('mousemove', (e) => {
                if (!isDragging) return;
                const rect = svg.getBoundingClientRect();
                const curX = e.clientX - rect.left;
                const curY = e.clientY - rect.top;
                // 将像素偏移转换为 viewBox 坐标偏移
                const dx = (curX - dragStart.x) * (vb.w / SVG_PIXEL_SIZE);
                const dy = (curY - dragStart.y) * (vb.h / SVG_PIXEL_SIZE);
                vb.x = vbStart.x - dx;
                vb.y = vbStart.y - dy;
                applyViewBox();
                // 拖动过程中仅预览，不更新分形 (由 mouseup 触发更新)
            });

            window.addEventListener('mouseup', (e) => {
                if (isDragging) {
                    isDragging = false;
                    svg.style.cursor = 'grab';
                    scheduleUpdate(100);
                }
            });

            // ----- 鼠标滚轮缩放 -----
            svg.addEventListener('wheel', (e) => {
                e.preventDefault();
                const rect = svg.getBoundingClientRect();
                const mouseX = (e.clientX - rect.left) / SVG_PIXEL_SIZE; // 0~1 比例
                const mouseY = (e.clientY - rect.top) / SVG_PIXEL_SIZE;
                // 将鼠标位置映射到 viewBox 坐标
                const vbMX = vb.x + mouseX * vb.w;
                const vbMY = vb.y + mouseY * vb.h;

                const factor = e.deltaY < 0 ? 0.9 : 1.1; // 向上滚动放大，向下缩小
                const newW = vb.w * factor;
                const newH = vb.h * factor;

                // 保持鼠标位置不变
                vb.x = vbMX - mouseX * newW;
                vb.y = vbMY - mouseY * newH;
                vb.w = newW;
                vb.h = newH;

                applyViewBox();
                scheduleUpdate(100);
            }, { passive: false });

            // ----- 按钮事件绑定 -----
            document.getElementById('zoomIn').addEventListener('click', zoomIn);
            document.getElementById('zoomOut').addEventListener('click', zoomOut);
            document.getElementById('moveUp').addEventListener('click', () => move(0, -vb.h * 0.15));
            document.getElementById('moveDown').addEventListener('click', () => move(0, vb.h * 0.15));
            document.getElementById('moveLeft').addEventListener('click', () => move(-vb.w * 0.15, 0));
            document.getElementById('moveRight').addEventListener('click', () => move(vb.w * 0.15, 0));
            document.getElementById('reset').addEventListener('click', resetView);

            // ----- 初始渲染 -----
            updateFractal();

        })();
    </script>
