<body>

<div class="game-container">
    <h1>✧ 井字棋 ✧</h1>
    <div class="status-area">
        <span class="turn-indicator" id="turnIndicator">🧑 玩家回合</span>
        <span class="game-status" id="gameStatus">进行中</span>
    </div>

    <div class="board" id="board">
        <!-- 9 个格子将由 JS 动态生成 -->
    </div>

    <button class="reset-btn" id="resetBtn">⟳ 重新开局</button>
    <div class="footer-note">你 · X &nbsp;&nbsp; AI · O &nbsp; (Minimax)</div>
</div>

<script>
    (function() {
        "use strict";

        // ----- 游戏状态 -----
        const board = Array(9).fill('');          // 一维数组 0~8 左上到右下
        let currentPlayer = 'X';                  // X 玩家, O AI
        let gameActive = true;
        let aiThinking = false;                  // 防止同时点击
        let winner = null;                       // 'X', 'O', 'tie', null

        // DOM 元素
        const boardEl = document.getElementById('board');
        const turnIndicator = document.getElementById('turnIndicator');
        const gameStatusEl = document.getElementById('gameStatus');
        const resetBtn = document.getElementById('resetBtn');

        // 创建格子
        for (let i = 0; i < 9; i++) {
            const cell = document.createElement('button');
            cell.classList.add('cell');
            cell.dataset.index = i;
            boardEl.appendChild(cell);
        }
        const cells = boardEl.querySelectorAll('.cell');

        // ----- 工具函数 -----
        function updateUI() {
            // 更新棋盘显示
            cells.forEach((cell, idx) => {
                const mark = board[idx];
                cell.textContent = mark;
                // 重置所有类，保留 win-highlight（如果有）
                cell.classList.remove('x-mark', 'o-mark', 'disabled');
                if (mark === 'X') cell.classList.add('x-mark');
                else if (mark === 'O') cell.classList.add('o-mark');
                if (!gameActive || aiThinking || mark !== '' || currentPlayer === 'O') {
                    cell.classList.add('disabled');
                }
            });

            // 更新轮次 & 状态
            if (!gameActive) {
                // 游戏结束后，确保胜利高亮重新显示
                if (winner === 'X' || winner === 'O') {
                    highlightWinLine();
                }

                if (winner === 'X') {
                    turnIndicator.textContent = '🎉 玩家胜！';
                    turnIndicator.className = 'turn-indicator player-turn';
                    gameStatusEl.textContent = '玩家赢';
                } else if (winner === 'O') {
                    turnIndicator.textContent = '🤖 AI 胜！';
                    turnIndicator.className = 'turn-indicator ai-turn';
                    gameStatusEl.textContent = 'AI赢';
                } else if (winner === 'tie') {
                    turnIndicator.textContent = '🤝 平局';
                    turnIndicator.className = 'turn-indicator';
                    gameStatusEl.textContent = '平局';
                }
                // 禁用所有格子（已经在上面设置过了）
                return;
            }

            // 游戏进行中
            if (currentPlayer === 'X') {
                turnIndicator.textContent = '🧑 玩家回合';
                turnIndicator.className = 'turn-indicator player-turn';
            } else {
                turnIndicator.textContent = '🤖 AI 思考中…';
                turnIndicator.className = 'turn-indicator ai-turn';
            }
            gameStatusEl.textContent = '进行中';
        }

        // 检查胜负 / 平局  返回 'X', 'O', 'tie', 或 null
        function checkWinner() {
            const lines = [
                [0,1,2],[3,4,5],[6,7,8], // 行
                [0,3,6],[1,4,7],[2,5,8], // 列
                [0,4,8],[2,4,6]          // 对角线
            ];
            for (const [a,b,c] of lines) {
                if (board[a] && board[a] === board[b] && board[a] === board[c]) {
                    return board[a];  // 'X' 或 'O'
                }
            }
            if (board.every(cell => cell !== '')) return 'tie';
            return null;
        }

        // 高亮获胜连线（应用 win-highlight 类）
        function highlightWinLine() {
            // 先清除所有高亮，避免重复
            cells.forEach(c => c.classList.remove('win-highlight'));

            const lines = [
                [0,1,2],[3,4,5],[6,7,8],
                [0,3,6],[1,4,7],[2,5,8],
                [0,4,8],[2,4,6]
            ];
            for (const [a,b,c] of lines) {
                if (board[a] && board[a] === board[b] && board[a] === board[c]) {
                    cells[a].classList.add('win-highlight');
                    cells[b].classList.add('win-highlight');
                    cells[c].classList.add('win-highlight');
                    break;
                }
            }
        }

        // 切换玩家
        function switchPlayer() {
            currentPlayer = currentPlayer === 'X' ? 'O' : 'X';
        }

        // 游戏结束处理
        function endGame(result) {
            gameActive = false;
            winner = result;
            // 先高亮胜利线，再调用 updateUI 会保持高亮（或重新高亮）
            if (result === 'X' || result === 'O') {
                highlightWinLine();
            }
            updateUI();
        }

        // ----- 核心：Minimax AI -----
        function minimax(boardState, depth, isMaximizing) {
            // 评估当前局面
            const result = evaluateBoard(boardState);
            // 终止条件
            if (result === 10) return 10 - depth;   // AI 胜，优先浅层
            if (result === -10) return -10 + depth; // 玩家胜，优先深层（拖延）
            if (isBoardFull(boardState)) return 0;  // 平局

            if (isMaximizing) {
                let best = -Infinity;
                for (let i = 0; i < 9; i++) {
                    if (boardState[i] === '') {
                        boardState[i] = 'O'; // AI 下
                        const score = minimax(boardState, depth + 1, false);
                        boardState[i] = '';
                        best = Math.max(score, best);
                    }
                }
                return best;
            } else {
                let best = Infinity;
                for (let i = 0; i < 9; i++) {
                    if (boardState[i] === '') {
                        boardState[i] = 'X'; // 玩家下
                        const score = minimax(boardState, depth + 1, true);
                        boardState[i] = '';
                        best = Math.min(score, best);
                    }
                }
                return best;
            }
        }

        function evaluateBoard(boardState) {
            // 检查是否有胜者
            const winLines = [
                [0,1,2],[3,4,5],[6,7,8],
                [0,3,6],[1,4,7],[2,5,8],
                [0,4,8],[2,4,6]
            ];
            for (const [a,b,c] of winLines) {
                if (boardState[a] && boardState[a] === boardState[b] && boardState[a] === boardState[c]) {
                    if (boardState[a] === 'O') return 10;   // AI 赢
                    else if (boardState[a] === 'X') return -10; // 玩家赢
                }
            }
            return 0; // 无胜者
        }

        function isBoardFull(boardState) {
            return boardState.every(cell => cell !== '');
        }

        // AI 选择最佳落子（返回索引）
        function getBestMove() {
            let bestScore = -Infinity;
            let bestMove = -1;
            // 深拷贝棋盘用于搜索
            const boardCopy = [...board];

            for (let i = 0; i < 9; i++) {
                if (boardCopy[i] === '') {
                    boardCopy[i] = 'O';
                    const moveScore = minimax(boardCopy, 0, false);
                    boardCopy[i] = '';
                    if (moveScore > bestScore) {
                        bestScore = moveScore;
                        bestMove = i;
                    }
                }
            }
            return bestMove;
        }

        // ----- 玩家落子处理 -----
        function handlePlayerMove(index) {
            if (!gameActive || aiThinking || currentPlayer !== 'X' || board[index] !== '') return;

            // 放置 X
            board[index] = 'X';
            updateUI();

            // 检查胜负
            const result = checkWinner();
            if (result) {
                endGame(result);
                return;
            }

            // 切换至 AI
            switchPlayer(); // currentPlayer -> 'O'
            updateUI();

            // 触发 AI 走棋（异步）
            aiThinking = true;
            setTimeout(() => {
                aiMove();
            }, 400); // 400ms 延迟，让玩家看到切换
        }

        // AI 走棋
        function aiMove() {
            if (!gameActive || currentPlayer !== 'O') {
                aiThinking = false;
                updateUI();
                return;
            }

            const move = getBestMove();
            if (move === -1) {
                // 无可用的子（理论上不会发生，因为先检查了胜负和满盘）
                aiThinking = false;
                updateUI();
                return;
            }

            board[move] = 'O';
            updateUI();

            // 检查结果
            const result = checkWinner();
            if (result) {
                endGame(result);
                aiThinking = false;
                return;
            }

            // 切换回玩家
            switchPlayer(); // currentPlayer -> 'X'
            aiThinking = false;
            updateUI();
        }

        // ----- 重置游戏 -----
        function resetGame() {
            // 清除所有标记
            for (let i = 0; i < 9; i++) board[i] = '';
            currentPlayer = 'X';
            gameActive = true;
            aiThinking = false;
            winner = null;
            // 移除高亮
            cells.forEach(c => c.classList.remove('win-highlight'));
            updateUI();
        }

        // ----- 事件绑定 -----
        boardEl.addEventListener('click', (e) => {
            const cell = e.target.closest('.cell');
            if (!cell) return;
            const index = parseInt(cell.dataset.index, 10);
            handlePlayerMove(index);
        });

        resetBtn.addEventListener('click', resetGame);

        // 初始化界面
        resetGame();

        console.log('井字棋已启动，AI使用Minimax算法。');
    })();
</script>

</body>
</html>
