        <button onclick="appendNumber(2)">2</button>
        <button onclick="appendNumber(3)">3</button>
        <button class="function" onclick="unaryOp('inverse')">1/x</button>

        <button class="zero" onclick="appendNumber(0)">0</button>
        <button onclick="appendDot()">.</button>
        <button class="function" onclick="toggleSign()">±</button>
    </div>
</div>

<script>
    // 状态变量
    let currentInput = '';      // 当前输入的字符串（数字或计算中间结果）
    let previousValue = null;   // 前一个操作数（用于二元运算）
    let operator = null;        // 当前运算符
    let resetNext = false;      // 下次输入数字时是否重置显示
    let justCalculated = false; // 标记是否刚刚按了等号或一元函数，用于连续运算

    // DOM 元素
    const expressionEl = document.getElementById('expression');
    const resultEl = document.getElementById('result');

    function updateDisplay() {
        // 显示当前输入，如果为空则显示0
        let display = currentInput === '' ? '0' : currentInput;
        resultEl.textContent = display;
        // 表达式栏显示当前运算状态（可选）
        if (operator && previousValue !== null) {
            expressionEl.textContent = previousValue + ' ' + operator + ' ' + (currentInput === '' ? '?' : currentInput);
        } else {
            expressionEl.textContent = '';
        }
    }

    function appendNumber(num) {
        if (resetNext) {
            currentInput = '';
            resetNext = false;
        }
        if (justCalculated) {
            // 如果刚计算完，输入数字则开始新输入
            currentInput = '';
            previousValue = null;
            operator = null;
            justCalculated = false;
        }
        currentInput += num.toString();
        updateDisplay();
    }

    function appendDot() {
        if (resetNext) {
            currentInput = '';
            resetNext = false;
        }
        if (justCalculated) {
            currentInput = '';
            previousValue = null;
            operator = null;
            justCalculated = false;
        }
        // 避免多个小数点
        if (currentInput.includes('.')) return;
        if (currentInput === '') currentInput = '0';
        currentInput += '.';
        updateDisplay();
    }

    function toggleSign() {
        if (currentInput === '' || currentInput === '0') return;
        if (currentInput.startsWith('-')) {
            currentInput = currentInput.slice(1);
        } else {
            currentInput = '-' + currentInput;
        }
        updateDisplay();
    }

    function appendPercent() {
        if (currentInput === '') return;
        let value = parseFloat(currentInput);
        if (isNaN(value)) return;
        let result = value / 100;
        currentInput = formatNumber(result);
        updateDisplay();
    }

    function backspace() {
        if (currentInput.length > 0) {
            currentInput = currentInput.slice(0, -1);
            updateDisplay();
        }
    }

    function clearAll() {
        currentInput = '';
        previousValue = null;
        operator = null;
        resetNext = false;
        justCalculated = false;
        expressionEl.textContent = '';
        resultEl.textContent = '0';
    }

    function setOperator(op) {
        if (operator && previousValue !== null && currentInput !== '') {
            // 有悬而未决的运算，先计算
            calculate(true);
        }
        if (currentInput === '') {
            // 如果没有输入数字，但可能有一个之前的计算结果，可以重复使用运算符
            if (previousValue !== null) {
                // 直接设置运算符，显示不变
                operator = op;
                updateDisplay();
                return;
            } else {
                // 无输入也无前值，忽略
                return;
            }
        }
        // 保存当前输入到 previousValue
        previousValue = parseFloat(currentInput);
        if (isNaN(previousValue)) {
            previousValue = 0;
        }
        operator = op;
        resetNext = true;
        justCalculated = false;
        updateDisplay();
    }

    function calculate(keepResult = false) {
        // keepResult 用于链式运算，不重置状态
        if (operator && previousValue !== null) {
            let currentValue = parseFloat(currentInput);
            if (isNaN(currentValue)) currentValue = 0;
            let result;
            switch (operator) {
                case '+': result = previousValue + currentValue; break;
                case '-': result = previousValue - currentValue; break;
                case '×': result = previousValue * currentValue; break;
                case '÷': 
                    if (currentValue === 0) {
                        result = '错误';
                    } else {
                        result = previousValue / currentValue;
                    }
                    break;
                default: result = currentValue;
            }
            if (result === '错误') {
                currentInput = '错误';
                previousValue = null;
                operator = null;
                updateDisplay();
                return;
            }
            currentInput = formatNumber(result);
            // 如果 keepResult 为 false，则清除运算符状态（等号按下）
            if (!keepResult) {
                previousValue = null;
                operator = null;
                justCalculated = true;
                resetNext = true;
            } else {
                // 保持 previousValue 为当前结果，以便连续运算
                previousValue = result;
                resetNext = true;
            }
            updateDisplay();
        } else {
            // 没有运算符，只是显示数字
            justCalculated = true;
        }
    }

    function unaryOp(func) {
        // 获取当前操作数
        let value = parseFloat(currentInput);
        if (isNaN(value)) {
            // 如果当前输入为空，尝试使用 previousValue
            if (previousValue !== null && !resetNext) {
                value = previousValue;
            } else {
                value = 0;
            }
        }
        let result;
        switch (func) {
            case 'sin':
                result = Math.sin(toRadians(value));
                break;
            case 'cos':
                result = Math.cos(toRadians(value));
                break;
            case 'tan':
                result = Math.tan(toRadians(value));
                break;
            case 'log':
                result = Math.log10(value);
                break;
            case 'ln':
                result = Math.log(value);
                break;
            case 'sqrt':
                if (value < 0) {
                    result = '错误';
                } else {
                    result = Math.sqrt(value);
                }
                break;
            case 'exp':
                result = Math.exp(value);
                break;
            case 'pow2':
                result = Math.pow(2, value);
                break;
            case 'pow10':
                result = Math.pow(10, value);
                break;
            case 'factorial':
                if (value < 0 || !Number.isInteger(value)) {
                    result = '错误';
                } else {
                    result = factorial(Math.round(value));
                }
                break;
            case 'inverse':
                if (value === 0) {
                    result = '错误';
                } else {
                    result = 1 / value;
                }
                break;
            default:
                result = value;
        }
        if (result === '错误') {
            currentInput = '错误';
            previousValue = null;
            operator = null;
            updateDisplay();
            return;
        }
        currentInput = formatNumber(result);
        // 一元函数后，将结果作为前值，允许继续运算
        previousValue = result;
        resetNext = true;
        justCalculated = true;
        updateDisplay();
    }

    function toRadians(deg) {
        return deg * Math.PI / 180;
    }

    function factorial(n) {
        if (n === 0 || n === 1) return 1;
        let result = 1;
        for (let i = 2; i <= n; i++) {
            result *= i;
        }
        return result;
    }

    function formatNumber(num) {
        if (typeof num === 'number') {
            // 避免浮点精度过长
            if (Number.isInteger(num) && Math.abs(num) < 1e15) {
                return num.toString();
            } else {
                // 保留最多10位有效数字
                return parseFloat(num.toPrecision(10)).toString();
            }
        }
        return num.toString();
    }

    // 键盘支持（可选）
    document.addEventListener('keydown', function(e) {
        const key = e.key;
        if (key >= '0' && key <= '9') {
            appendNumber(parseInt(key));
        } else if (key === '.') {
            appendDot();
        } else if (key === 'Enter' || key === '=') {
            e.preventDefault();
            calculate();
        } else if (key === 'Backspace') {
            backspace();
        } else if (key === 'Escape' || key === 'c' || key === 'C') {
            clearAll();
        } else if (key === '+' || key === '-' || key === '*' || key === '/') {
            let op;
            if (key === '+') op = '+';
            else if (key === '-') op = '-';
            else if (key === '*') op = '×';
            else if (key === '/') op = '÷';
            setOperator(op);
        } else if (key === '%') {
            appendPercent();
        }
    });

    // 初始化显示
    updateDisplay();
</script>
</body>
</html>
